// C3: Physical sensing components
instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor encoder measuring motor shaft angle before gearbox"
    DTDFVocab:producedData MotorEncoderAngleTopic
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder positioned behind the gearbox measuring output shaft angle"
    DTDFVocab:producedData GearboxEncoderAngleTopic
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring motor phase current I_M"
    DTDFVocab:producedData MotorCurrentTopic
]

// C4: Physical-to-virtual interaction – DataTransmitted
instance MotorEncoderAngleTopic : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxEncoderAngleTopic : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

instance MotorCurrentTopic : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C10: Data
instance MotorAngleData : DTDFVocab:Data [
    base:desc "Time‑series of motor shaft angle from MotorEncoder"
    DTDFVocab:fromData MotorEncoderAngleTopic
    DTDFVocab:inputTo EnablerMqtt, EnablerSimulink
]

instance GearboxAngleData : DTDFVocab:Data [
    base:desc "Time‑series of gearbox output angle from GearboxEncoder"
    DTDFVocab:fromData GearboxEncoderAngleTopic
    DTDFVocab:inputTo EnablerMqtt, EnablerSimulink
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Time‑series of motor phase current I_M from MotorCurrentSensor"
    DTDFVocab:fromData MotorCurrentTopic
    DTDFVocab:inputTo EnablerMqtt, EnablerSimulink
]

instance TorqueData : DTDFVocab:Data [
    base:desc "Derived torque τ calculated from current and model"
    DTDFVocab:fromData MotorCurrentTopic
    DTDFVocab:inputTo EnablerSimulink
]

instance AngularVelocityData : DTDFVocab:Data [
    base:desc "Derived angular velocity ω computed from angle derivatives"
    DTDFVocab:fromData MotorEncoderAngleTopic
    DTDFVocab:inputTo EnablerSimulink
]

// C11: Enablers
instance EnablerMqtt : DTDFVocab:Enabler [
    base:desc "MQTT broker for streaming sensor time‑series data"
    DTDFVocab:enables RealTimeVisualizationService, FrictionParameterIdentificationService
]

instance EnablerSimulink : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink execution environment for friction models and identification algorithms"
    DTDFVocab:enables FrictionParameterIdentificationService, FrictionModelProvisionService
]

instance EnablerWebDashboard : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard consuming MQTT topics for real‑time visualization"
    DTDFVocab:enables RealTimeVisualizationService
]

// C6: Services
instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Real‑time visualization dashboard of axis motion and friction parameters"
    DTDFVocab:provides MotionVisualizationInsight
]

instance FrictionParameterIdentificationService : DTDFVocab:Service [
    base:desc "Service identifying static, kinetic and viscous friction parameters using Simulink models"
    DTDFVocab:provides FrictionParameterInsight
]

instance FrictionModelProvisionService : DTDFVocab:Service [
    base:desc "Provision of updated friction models to the robot controller for improved motion accuracy"
    DTDFVocab:provides UpdateControlLawAction
]

// C17: Insights / Actions
instance MotionVisualizationInsight : DTDFVocab:Insight [
    base:desc "Operators can monitor live axis position, velocity and torque"
]

instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Identified friction parameters enable tuning of control laws"
]

instance UpdateControlLawAction : DTDFVocab:Action [
    base:desc "Robot controller receives updated friction model and adjusts control gains"
    DTDFVocab:IsAutomatic true
]

// C10: Models (engineering & executable)
instance SysMLStructuralModel : DTDFVocab:Model [
    base:desc "SysML block definition and internal block diagrams of the first robot axis"
    DTDFVocab:inputTo EnablerWebDashboard
]

instance SimulinkFrictionIdentificationModel : DTDFVocab:Model [
    base:desc "Simulink model for friction‑parameter identification (Coulomb‑Viscous, Stribeck, Dahl, LuGre)"
    DTDFVocab:inputTo EnablerSimulink
]

instance SimulinkGearboxModel : DTDFVocab:Model [
    base:desc "Executable simulation of friction‑less gearbox in Simulink"
    DTDFVocab:inputTo EnablerSimulink
]

// C18: Environment (contextual grouping)
instance RobotAxisEnvironment : DTDFVocab:Environment [
    base:contains MotorEncoder, GearboxEncoder, MotorCurrentSensor, EnablerMqtt, EnablerSimulink, EnablerWebDashboard
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A digital shadow comprising a Purpose (FrictionDerivation), Asset (MABI first axis), Sources (sensor channels), Processing components (Simulation M, GW, GB) that consume input traces and produce simulated traces, and data traces linked to models for traceability and friction analysis."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Full traceability of each DataPoint to its generating model and processing component; comparison of simulated vs. measured traces to evaluate model fidelity; multi‑physics aware identification of joint friction; semantic linking of data series to structural model for validation."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are streamed from the robot to the digital shadow using the MQTT protocol; the shadow aggregates these streams into DataTraces."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of Asset Administration Shells (AAS) as an Industry 4.0 standard for model integration; SysML as a standardized modeling language."
]
